# ── cross-module imports ─────────────────────────────────────────────────
from ..utils.text import normalize_work_text, trim

class TodoManager:
    def __init__(self):
        self.items: list[dict] = []
        self.lock = threading.Lock()

    def update(self, items: list[dict]) -> str:
        if not isinstance(items, list):
            raise ValueError("items must be array")
        validated = []
        # Plan-step items (bb:proj: key) and worker/non-plan items each get their
        # own in_progress slot, so a plan step in_progress doesn't demote worker subtasks.
        plan_in_progress_seen = False
        worker_in_progress_seen = False
        status_alias = {
            "todo": "pending",
            "doing": "in_progress",
            "inprogress": "in_progress",
            "in-progress": "in_progress",
            "done": "completed",
            "finish": "completed",
            "finished": "completed",
        }
        for idx, item in enumerate(items):
            if isinstance(item, str):
                raw = {"content": item, "status": "pending"}
            elif isinstance(item, dict):
                raw = item
            else:
                raise ValueError(f"item {idx}: invalid type")
            raw_content = str(raw.get("content", raw.get("text", raw.get("title", "")))).strip()
            content = normalize_work_text(raw_content)
            if not content:
                content = raw_content
            if not content:
                raise ValueError(f"item {idx}: content required")
            raw_status = str(raw.get("status", raw.get("state", "pending"))).strip().lower()
            status = status_alias.get(raw_status, raw_status or "pending")
            if status not in {"pending", "in_progress", "completed"}:
                status = "pending"
            content = normalize_work_text(content, status) or content
            active_form = str(
                raw.get(
                    "activeForm",
                    raw.get("active_form", raw.get("action", raw.get("current", ""))),
                )
            ).strip()
            owner = str(raw.get("owner", "") or "").strip().lower()
            if owner not in {"manager", "explorer", "developer", "reviewer"}:
                owner = ""
            key = trim(str(raw.get("key", "") or "").strip(), 120)
            is_plan_step = key.startswith("bb:proj:")
            if status == "in_progress":
                if is_plan_step:
                    if plan_in_progress_seen:
                        status = "pending"
                    else:
                        plan_in_progress_seen = True
                else:
                    if worker_in_progress_seen:
                        status = "pending"
                    else:
                        worker_in_progress_seen = True
            if not active_form:
                if status == "in_progress":
                    active_form = f"Working on: {content}"
                elif status == "completed":
                    active_form = f"Completed: {content}"
                else:
                    active_form = f"Pending: {content}"
            row = {"content": content, "status": status, "activeForm": active_form}
            if owner:
                row["owner"] = owner
            if key:
                row["key"] = key
            validated.append(row)
        if len(validated) > 20:
            raise ValueError("max 20 todos")
        if validated and not any(x["status"] == "in_progress" for x in validated):
            for row in validated:
                if row["status"] == "pending":
                    row["status"] = "in_progress"
                    row["activeForm"] = row.get("activeForm") or f"Working on: {row['content']}"
                    break
        with self.lock:
            if self.items == validated:
                return "No todo changes."
            self.items = validated
        return self.render()

    def has_open_items(self) -> bool:
        with self.lock:
            return any(x.get("status") != "completed" for x in self.items)

    def render(self) -> str:
        with self.lock:
            items = list(self.items)
        if not items:
            return "No todos."
        lines = []
        for item in items:
            marker = {"completed": "[x]", "in_progress": "[>]", "pending": "[ ]"}.get(
                item["status"], "[?]"
            )
            suffix = (
                f" <- {item['activeForm']}" if item["status"] == "in_progress" else ""
            )
            lines.append(f"{marker} {item['content']}{suffix}")
        done = sum(1 for x in items if x["status"] == "completed")
        lines.append(f"\n({done}/{len(items)} completed)")
        return "\n".join(lines)

    def snapshot(self) -> list[dict]:
        with self.lock:
            return [dict(x) for x in self.items]

    def complete_active(self, summary: str = "") -> dict:
        note = trim(str(summary or "").strip(), 180)
        with self.lock:
            rows = [dict(x) for x in self.items]
            if not rows:
                return {"updated": 0, "total": 0, "open_before": 0}
            open_before = sum(1 for x in rows if str(x.get("status", "pending")) != "completed")
            in_progress_indexes = [
                idx for idx, row in enumerate(rows) if str(row.get("status", "pending")) == "in_progress"
            ]
            changed = 0
            if in_progress_indexes:
                for idx in in_progress_indexes:
                    rows[idx]["status"] = "completed"
                    base = normalize_work_text(str(rows[idx].get("content", "")).strip()) or str(
                        rows[idx].get("content", "")
                    ).strip()
                    suffix = f" ({note})" if note else ""
                    rows[idx]["activeForm"] = f"Completed: {base}{suffix}".strip()
                    changed += 1
            else:
                for idx, row in enumerate(rows):
                    if str(row.get("status", "pending")) == "pending":
                        rows[idx]["status"] = "completed"
                        base = normalize_work_text(str(rows[idx].get("content", "")).strip()) or str(
                            rows[idx].get("content", "")
                        ).strip()
                        suffix = f" ({note})" if note else ""
                        rows[idx]["activeForm"] = f"Completed: {base}{suffix}".strip()
                        changed = 1
                        break
            if changed > 0:
                self.items = rows
            return {"updated": int(changed), "total": len(rows), "open_before": int(open_before)}

    def complete_all_open(self, summary: str = "") -> dict:
        note = trim(str(summary or "").strip(), 180)
        with self.lock:
            rows = [dict(x) for x in self.items]
            if not rows:
                return {"updated": 0, "total": 0, "open_before": 0}
            open_before = sum(1 for x in rows if str(x.get("status", "pending")) != "completed")
            changed = 0
            for idx, row in enumerate(rows):
                status = str(row.get("status", "pending"))
                if status == "completed":
                    continue
                rows[idx]["status"] = "completed"
                base = normalize_work_text(str(rows[idx].get("content", "")).strip()) or str(
                    rows[idx].get("content", "")
                ).strip()
                suffix = f" ({note})" if note else ""
                rows[idx]["activeForm"] = f"Completed: {base}{suffix}".strip()
                changed += 1
            if changed > 0:
                self.items = rows
            return {"updated": int(changed), "total": len(rows), "open_before": int(open_before)}

    def clear_all(self) -> dict:
        with self.lock:
            total = len(self.items)
            open_count = sum(1 for x in self.items if str(x.get("status", "pending")) != "completed")
            self.items = []
        return {"removed": int(total), "open_removed": int(open_count)}

